query:
SELECT `id`, JSON_UNQUOTE(JSON_EXTRACT(`metadata`, '$.ePhotoSyncStatus')) AS sync_status, JSON_UNQUOTE(JSON_EXTRACT(`metadata`, '$.eFrontPhotoUrl')) AS front_url, JSON_UNQUOTE(JSON_EXTRACT(`metadata`, '$.eBackPhotoUrl')) AS back_url, JSON_EXTRACT(`metadata`, '$.ePhotoPendingUploads.front') AS pending_front, JSON_EXTRACT(`metadata`, '$.ePhotoPendingUploads.back') AS pending_back, JSON_UNQUOTE(JSON_EXTRACT(`metadata`, '$.ePhotoSyncMessage')) AS sync_message
FROM `station_tasks`
WHERE `id` = 510875;

